import React, { useEffect, useMemo, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { toast } from 'react-toastify';
import {
  createCategory,
  deleteCategory,
  getCategories,
  updateCategory
} from '../api/categoriesApi';
import {
  createProduct,
  deleteProduct,
  getProducts,
  updateProduct
} from '../api/productsApi';
import ConfirmModal from '../components/modals/ConfirmModal';
import { setCategories, setProducts } from '../redux/actions/shopActions';

const AdminPage = () => {
  const dispatch = useDispatch();
  const products = useSelector((state) => state.shop.products);
  const categories = useSelector((state) => state.shop.categories);
  const [productForm, setProductForm] = useState({
    name: '',
    price: '',
    img: '',
    categoryId: ''
  });
  const [categoryForm, setCategoryForm] = useState({ name: '' });
  const [editProductId, setEditProductId] = useState(null);
  const [editCategoryId, setEditCategoryId] = useState(null);
  const [deleteState, setDeleteState] = useState(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        const [productsData, categoriesData] = await Promise.all([
          getProducts(),
          getCategories()
        ]);

        dispatch(setProducts(productsData));
        dispatch(setCategories(categoriesData));
      } catch (error) {
        toast.error('Could not load admin data.');
      }
    };

    loadData();
  }, [dispatch]);

  useEffect(() => {
    if (!productForm.categoryId && categories.length > 0) {
      setProductForm((current) => ({
        ...current,
        categoryId: categories[0].id
      }));
    }
  }, [categories, productForm.categoryId]);

  const categoryMap = useMemo(
    () => Object.fromEntries(categories.map((category) => [category.id, category.name])),
    [categories]
  );

  const resetCategoryForm = () => {
    setEditCategoryId(null);
    setCategoryForm({ name: '' });
  };

  const resetProductForm = () => {
    setEditProductId(null);
    setProductForm({
      name: '',
      price: '',
      img: '',
      categoryId: categories[0]?.id || ''
    });
  };

  const handleCategorySubmit = async (e) => {
    e.preventDefault();

    const payload = { name: categoryForm.name.trim() };

    try {
      const data = editCategoryId
        ? await updateCategory(editCategoryId, payload)
        : await createCategory(payload);

      if (editCategoryId) {
        dispatch(
          setCategories(
            categories.map((category) => (category.id === editCategoryId ? data : category))
          )
        );
        dispatch(
          setProducts(
            products.map((product) =>
              product.categoryId === editCategoryId
                ? { ...product, categoryName: data.name }
                : product
            )
          )
        );
      } else {
        dispatch(setCategories([...categories, data]));
      }

      resetCategoryForm();
      toast.success(editCategoryId ? 'Category updated successfully.' : 'Category created successfully.');
    } catch (error) {
      toast.error('Could not save category.');
    }
  };

  const handleProductSubmit = async (e) => {
    e.preventDefault();

    const selectedCategory = categories.find((category) => category.id === productForm.categoryId);
    const payload = {
      ...productForm,
      price: Number(productForm.price),
      categoryName: selectedCategory?.name || ''
    };

    try {
      const data = editProductId
        ? await updateProduct(editProductId, payload)
        : await createProduct(payload);

      if (editProductId) {
        dispatch(
          setProducts(products.map((product) => (product.id === editProductId ? data : product)))
        );
      } else {
        dispatch(setProducts([...products, data]));
      }

      resetProductForm();
      toast.success(editProductId ? 'Product updated successfully.' : 'Product created successfully.');
    } catch (error) {
      toast.error('Could not save product.');
    }
  };

  const askDelete = (type, item) => {
    setDeleteState({ type, item });
  };

  const handleDelete = async () => {
    if (!deleteState) {
      return;
    }

    const { type, item } = deleteState;

    try {
      if (type === 'product') {
        await deleteProduct(item.id);
        dispatch(setProducts(products.filter((product) => product.id !== item.id)));
        toast.success('Product deleted successfully.');
      } else {
        const relatedProducts = products.filter((product) => product.categoryId === item.id);

        if (relatedProducts.length > 0) {
          toast.error('Delete or move products from this category first.');
          return;
        }

        await deleteCategory(item.id);
        dispatch(setCategories(categories.filter((category) => category.id !== item.id)));
        toast.success('Category deleted successfully.');
      }

      setDeleteState(null);
    } catch (error) {
      toast.error(`Could not delete ${type}.`);
    }
  };

  return (
    <div className="container admin-page">
      <h2 className="page-title">РЈРїСЂР°РІР»РµРЅРёРµ РјР°РіР°Р·РёРЅРѕРј</h2>

      <div className="admin-grid">
        <div className="admin-form-box">
          <h3>{editCategoryId ? 'Edit category' : 'Create category'}</h3>

          <form onSubmit={handleCategorySubmit} className="admin-form">
            <input
              placeholder="Category name"
              value={categoryForm.name}
              onChange={(e) => setCategoryForm({ name: e.target.value })}
              required
            />

            <button type="submit" className={`button ${editCategoryId ? 'button-success' : ''}`}>
              {editCategoryId ? 'Save category' : 'Create category'}
            </button>

            {editCategoryId && (
              <button
                type="button"
                className="button button-secondary"
                onClick={resetCategoryForm}
              >
                Cancel
              </button>
            )}
          </form>
        </div>

        <div className="admin-form-box">
          <h3>{editProductId ? 'Edit product' : 'Create product'}</h3>

          <form onSubmit={handleProductSubmit} className="admin-form">
            <input
              placeholder="Product name"
              value={productForm.name}
              onChange={(e) => setProductForm({ ...productForm, name: e.target.value })}
              required
            />
            <input
              type="number"
              placeholder="Price"
              value={productForm.price}
              onChange={(e) => setProductForm({ ...productForm, price: e.target.value })}
              required
            />
            <input
              placeholder="Image URL"
              value={productForm.img}
              onChange={(e) => setProductForm({ ...productForm, img: e.target.value })}
              required
            />
            <select
              value={productForm.categoryId}
              onChange={(e) => setProductForm({ ...productForm, categoryId: e.target.value })}
              required
            >
              {categories.map((category) => (
                <option key={category.id} value={category.id}>
                  {category.name}
                </option>
              ))}
            </select>

            <button type="submit" className={`button ${editProductId ? 'button-success' : ''}`}>
              {editProductId ? 'Save product' : 'Create product'}
            </button>

            {editProductId && (
              <button
                type="button"
                className="button button-secondary"
                onClick={resetProductForm}
              >
                Cancel
              </button>
            )}
          </form>
        </div>
      </div>

      <table className="products-table">
        <thead>
          <tr>
            <th>Category</th>
            <th>Products</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {categories.map((category) => (
            <tr key={category.id}>
              <td>{category.name}</td>
              <td>{products.filter((product) => product.categoryId === category.id).length}</td>
              <td className="table-actions">
                <button
                  type="button"
                  className="button button-inline"
                  onClick={() => {
                    setEditCategoryId(category.id);
                    setCategoryForm({ name: category.name });
                    window.scrollTo(0, 0);
                  }}
                >
                  Edit
                </button>
                <button
                  type="button"
                  className="button button-danger button-inline"
                  onClick={() => askDelete('category', category)}
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      <table className="products-table">
        <thead>
          <tr>
            <th>Product</th>
            <th>Category</th>
            <th>Price</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id}>
              <td>{product.name}</td>
              <td>{categoryMap[product.categoryId] || product.categoryName}</td>
              <td>{product.price} KZT</td>
              <td className="table-actions">
                <button
                  type="button"
                  className="button button-inline"
                  onClick={() => {
                    setEditProductId(product.id);
                    setProductForm({
                      name: product.name,
                      price: product.price,
                      img: product.img,
                      categoryId: product.categoryId
                    });
                    window.scrollTo(0, 0);
                  }}
                >
                  Edit
                </button>
                <button
                  type="button"
                  className="button button-danger button-inline"
                  onClick={() => askDelete('product', product)}
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      <ConfirmModal
        isOpen={Boolean(deleteState)}
        title={deleteState?.type === 'category' ? 'Delete category?' : 'Delete product?'}
        description={
          deleteState?.type === 'category'
            ? 'This category will be removed if it has no products assigned to it.'
            : 'This product will be permanently removed from the catalog.'
        }
        confirmText="Delete"
        cancelText="Cancel"
        onConfirm={handleDelete}
        onClose={() => setDeleteState(null)}
      />
    </div>
  );
};

export default AdminPage;
